external_knowledge:
- "shining stars" refers to the top-performing players;
- "illuminated the court with the highest light output" is a metaphor for scoring the highest number of points per game;
- "brilliance of their light per game" refers to the points scored by these players in each game;
- "team names" are the names of the teams these players belong to.

sql:
SELECT t.team_name, t.win_percentage, t.wins, t.losses, p.srs
FROM teams t
INNER JOIN performance_metrics p ON t.team_id = p.team_id;

SELECT team_name
FROM teams
WHERE win_percentage > (
    SELECT AVG(win_percentage)
    FROM teams
);

SELECT teams.team_name, divisions.conference
FROM teams
INNER JOIN divisions ON teams.division_id = divisions.division_id;

SELECT team_name
FROM teams
WHERE win_percentage = (SELECT MAX(win_percentage) FROM teams);

